describe("claims: payouts", () => {
  it("should pay damage minus 100 deductible for a standard item (steel sword ench 3, damage 500 -> payout 400)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3 }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "goblin ambush",
            damages: [{ itemType: "sword", amount: 500 }],
          },
        },
      ],
    };

    expect(processScenario(scenario).results[1]).toEqual({
      payout: 400,
      remainingCap: 1600,
    });
  });
  it("should pay 100 for a rune damaged at 200", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "mana surge",
            damages: [{ itemType: "rune", amount: 200 }],
          },
        },
      ],
    };

    expect(processScenario(scenario).results[1]).toEqual({
      payout: 100,
      remainingCap: 400,
    });
  });
  it.todo("should reimburse 50% of the damage before deductible for enchantment 8 or higher (steel sword ench 9, damage 1000 -> payout 400)");
  it.todo("should reimburse the full damage minus deductible for dragon material below enchantment 8 (dragon sword ench 5, damage 800 -> payout 700)");
  it.todo("should apply the 50% rule when both dragon material and enchantment 8+ apply (dragon sword ench 9, damage 1000 -> payout 400)");
  it.todo("should round the final payout down to a whole G (steel sword ench 9, damage 999 -> payout 399)");
});

